import json

import pytest

from conftest import build_cache, run_script, write_blast_radius_map, read_json
import graphify_lib

AC_UID = "98a1420ab9b1d15c"
AC_TYPE = "data"


def test_AC14(real_binary, fixture_env):
    """
    GIVEN: built cache for the AC8 controlled fixture chosen so the focused subgraph has >=2 nodes and >=1 link + blast-radius-map with >=1 resolving path
    WHEN:  graphify-enrich.py patches graph_context into context-{ts}.json (and Step 1.5 structural_context in pre_query.json)
    THEN:  graph_context MUST include NON-EMPTY machine-readable nodes[] and edges[]/relations[] (empty arrays REJECTED as vacuous); every emitted node has id+label+source_file EXACTLY matching graph.json node; every emitted edge/relation has source+target+relation EXACTLY matching a graph.json link; >=1 emitted node's source_file is the modified fixture file AND exists on disk. Summary-only/count-only/id-only FAILS even if token counts/metadata also present. Token cap <=2000.
    """
    build_cache(fixture_env, real_binary)
    write_blast_radius_map(fixture_env, ["mod_b.py"])
    ctx = fixture_env["src"] / "context.json"
    ctx.write_text('{"task_id":"t1"}', encoding="utf-8")
    r = run_script("graphify-enrich.py", ["--task-id", "t1", "--context-file", str(ctx)],
                   fixture_env["env"])
    assert r.returncode == 0

    gc = read_json(ctx)["graph_context"]
    # Non-empty machine-readable arrays (empty arrays rejected).
    assert isinstance(gc["nodes"], list) and len(gc["nodes"]) >= 2
    assert isinstance(gc["edges"], list) and len(gc["edges"]) >= 1

    # Load the real graph.json to verify EXACT matches.
    graph, _ = graphify_lib.load_graph(fixture_env["graph_json"])
    g_nodes = {n["id"]: n for n in graph["nodes"]}
    g_links = {(l["source"], l["target"], l.get("relation")) for l in graph["links"]}

    for node in gc["nodes"]:
        assert {"id", "label", "source_file"} <= set(node.keys())
        gn = g_nodes[node["id"]]
        assert node["label"] == gn.get("label")
        assert node["source_file"] == gn.get("source_file")
    for edge in gc["edges"]:
        assert {"source", "target", "relation"} <= set(edge.keys())
        assert (edge["source"], edge["target"], edge["relation"]) in g_links

    # >=1 emitted node's source_file is the modified fixture file AND exists on disk.
    assert any(n["source_file"] == "mod_b.py" for n in gc["nodes"])
    assert (fixture_env["src"] / "mod_b.py").exists()

    # Token cap.
    assert len(json.dumps(gc)) // 4 <= 2000
